import React, { HTMLAttributes } from 'react';
import { Box, type CommonProps, type ExpandProps } from '@contentful/f36-core';
import { getUsageCardStyles } from './UsageCard.styles';
import { Card } from '@contentful/f36-card';
import { cx } from 'emotion';

export type UsageCardProps = CommonProps &
  HTMLAttributes<HTMLDivElement> & {
    children?: React.ReactNode;
    header?: React.ReactNode;
    description?: React.ReactNode;
    /**
     * The type of the card.
     * @default 'usage'
     */
    variant?: 'usage' | 'info';
  };

function _UsageCard(
  props: ExpandProps<UsageCardProps>,
  ref: React.Ref<HTMLDivElement>,
) {
  const {
    children,
    className,
    header,
    description,
    variant = 'usage',
    testId = 'cf-ui-usage-card',
    ...otherProps
  } = props;
  const styles = getUsageCardStyles();

  return (
    <Card
      {...otherProps}
      className={cx(styles.usageCard(variant), className)}
      ref={ref}
      data-test-id={testId}
      padding="large"
    >
      <Box style={{ flex: 1 }}>
        {header}
        {children}
      </Box>
      {description && <Box>{description}</Box>}
    </Card>
  );
}

export const UsageCard = React.forwardRef(_UsageCard);
import { css } from 'emotion';
import tokens from '@contentful/f36-tokens';
import { UsageCardProps } from './UsageCard';

const variantToStyles = (variant: UsageCardProps['variant']) => {
  switch (variant) {
    case 'info':
      return {
        backgroundColor: tokens.gray100,
        border: `2px solid ${tokens.gray100}`,
      };
    default:
      return {
        border: `2px solid ${tokens.gray200}`,
      };
  }
};

export const getUsageCardStyles = () => ({
  usageCard: (variant: UsageCardProps['variant']) =>
    css({
      flexDirection: 'column',
      height: '100%',
      justifyContent: 'space-between',
      ...variantToStyles(variant),
    }),
});

export const getUsageCardDescriptionStyles = () => {
  return {
    usageCardDescription: css({
      color: tokens.gray500,
    }),
  };
};
import React, { forwardRef, type HTMLAttributes, type Ref } from 'react';
import { cx } from 'emotion';
import { Tooltip } from '@contentful/f36-tooltip';
import { type CommonProps } from '@contentful/f36-core';
import { Subheading } from '@contentful/f36-typography';
import { getUsageCardHeaderStyles } from './UsageCardHeader.styles';
import { InfoCircleIcon } from '@contentful/f36-icons';

export type UsageCardHeaderProps = {
  children?: React.ReactNode;
  title?: string;
  tooltip?: string;
} & CommonProps &
  HTMLAttributes<HTMLDivElement>;

function _UsageCardHeader(
  props: UsageCardHeaderProps,
  ref: Ref<HTMLDivElement>,
) {
  const {
    children,
    title,
    tooltip,
    className,
    testId = 'cf-ui-usage-card-header',
    ...otherProps
  } = props;
  const styles = getUsageCardHeaderStyles();

  return (
    <Subheading
      {...otherProps}
      ref={ref}
      className={cx(styles.usageCardHeader(tooltip), className)}
      testId={testId}
    >
      {title}
      {tooltip && (
        <Tooltip content={tooltip} className={styles.tooltip} placement="top">
          <InfoCircleIcon className={styles.infoIcon} size="medium" />
        </Tooltip>
      )}

      {children}
    </Subheading>
  );
}

export const UsageCardHeader = forwardRef(_UsageCardHeader);
import tokens from '@contentful/f36-tokens';
import { css } from 'emotion';

export const getUsageCardHeaderStyles = () => ({
  usageCardHeader: (tooltip?: string) =>
    css({
      width: '100%',
      ...(tooltip && {
        display: 'flex',
        alignItems: 'center',
        gap: tokens.spacing2Xs,
      }),
    }),
  tooltip: css({
    minWidth: 'max-content',
  }),
  infoIcon: css`
    span & {
      display: flex;
      alignitems: center;
    }
  `,
});
import React, { forwardRef, type HTMLAttributes, type Ref } from 'react';
import { cx } from 'emotion';
import { type CommonProps } from '@contentful/f36-core';
import { Caption } from '@contentful/f36-typography';
import { getUsageCardDescriptionStyles } from './UsageCard.styles';

export type UsageCardDescriptionProps = {
  children: React.ReactNode;
} & CommonProps &
  HTMLAttributes<HTMLDivElement>;

const _UsageCardDescription = (
  props: UsageCardDescriptionProps,
  ref: Ref<HTMLDivElement>,
) => {
  const {
    children,
    className,
    testId = 'cf-ui-usage-card-description',
    ...otherProps
  } = props;
  const styles = getUsageCardDescriptionStyles();

  return (
    <Caption
      {...otherProps}
      ref={ref}
      className={cx(styles.usageCardDescription, className)}
      testId={testId}
    >
      {children}
    </Caption>
  );
};

export const UsageCardDescription = forwardRef(_UsageCardDescription);
import { UsageCard as OriginalUsageCard } from './UsageCard';
import { UsageCardHeader } from './UsageCardHeader/UsageCardHeader';
import { UsageCardDescription } from './UsageCardDescription';

type CompoundUsageCard = typeof OriginalUsageCard & {
  Header: typeof UsageCardHeader;
  Description: typeof UsageCardDescription;
};

export const UsageCard = OriginalUsageCard as CompoundUsageCard;
UsageCard.Header = UsageCardHeader;
UsageCard.Description = UsageCardDescription;
